(window.webpackJsonp=window.webpackJsonp||[]).push([[83],{710:function(r,n){r.exports="\x3c!-- \r\ntitle: 03-shell操作技巧\r\nsort: \r\n--\x3e \r\n\r\n## 快捷键\r\n\r\n| 快捷键     | 用途                                       |\r\n| ---------- | ------------------------------------------ |\r\n| Ctrl+AEBFL | 开头、结尾、前、后、清屏                   |\r\n| Alt+BF     | 前一个单词、后…                            |\r\n| Ctrl+DTU   | 删除光标所在位置的字符、调换位置、剪贴该行 |\r\n| Alt+DTU    | 剪贴到词尾、单词调换位置、转大写           |\r\n| Ctrl+Y     | 粘贴                                       |\r\n| Alt+?      | 显示所有可能的自动补全                     |\r\n| Ctrl+R     | 反向增量搜索命令                           |\r\n| !!         | 上次执行的命令                             |\r\n\r\n## Shell环境\r\n\r\n> SHELL在环境中储存了环境变量和shell变量\r\n>\r\n> 环境变量: `/etc/profile`\r\n>\r\n> shell变量`~/.bashrc`\r\n\r\n`printenv`\r\n\r\n> 查看环境变量\r\n>\r\n> `printenv NAME` : 特定环境变量\r\n>\r\n> `set`or`echo $NAME`也可\r\n\r\n`set`\r\n\r\n> 设置shell选项\r\n\r\n`export`\r\n\r\n> 设置\r\n\r\n`alias`"}}]);